import{_ as i,o as a,c as n,ac as e}from"./chunks/framework.DnBnwVZk.js";const F=JSON.parse('{"title":"ZeroTier-One搭建moon节点","description":"","frontmatter":{"date":"2021-03-18T00:00:00.000Z","categories":["Linux"],"tags":["Zerotier"],"publish":true},"headers":[],"relativePath":"views/linux/net/ZerotierOneAddMoon.md","filePath":"views/linux/net/ZerotierOneAddMoon.md","lastUpdated":1775803235000}'),t={name:"views/linux/net/ZerotierOneAddMoon.md"};function l(h,s,p,o,r,k){return a(),n("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1616025600000"},[...s[0]||(s[0]=[e(`<h1 id="zerotier-one搭建moon节点" tabindex="-1">ZeroTier-One搭建moon节点 <a class="header-anchor" href="#zerotier-one搭建moon节点" aria-label="Permalink to &quot;ZeroTier-One搭建moon节点&quot;">​</a></h1><p><a href="https://zhuanlan.zhihu.com/p/123956151" target="_blank" rel="noreferrer">原文链接</a></p><p>Zerotier可以组建虚拟局域网，并且是P2P直连的，这个可以说是非常爽了，你可以在公司使用微软自带的远程连接直连自己家里边的电脑，访问共享远程控制等。想要P2P访问必须先通过一个中介进行连接，官方的节点在网络高峰期不是很好使，所以最好在vps上建立一个moon节点。</p><p>作为Moon服务器不需要具备太强大的CPU性能/内存空间和存储空间，虚拟机、VPS、或者云服务器甚至一个树莓派都行，我自己使用的vps是<a href="https://passport.ucloud.cn/?invitation_code=C1x5D7234C844EE" target="_blank" rel="noreferrer">Ucloud</a>，首次注册可以买270块3年2M的主机，1C2G的配置，性价比还是很高的，关键是<strong>2M</strong>带宽，对于转发的提升是很明显的</p><h2 id="安装配置zerotier" tabindex="-1">安装配置ZeroTier <a class="header-anchor" href="#安装配置zerotier" aria-label="Permalink to &quot;安装配置ZeroTier&quot;">​</a></h2><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://install.zerotier.com</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zerotier-one.service</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zerotier-one.service</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 客户端执行：将安装好ZeroTier的加入你事先注册好的ZeroTier虚拟局域网中</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zerotier-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> join</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> asdfasdf</span></span></code></pre></div><p>此处的asdfasdf是本人ZeroTier虚拟局域网的ID，请更改为你本人自己的network ID</p><p>然后去zerotier管理页面，对加入的设备进行打钩</p><h2 id="搭建moon中转服务器" tabindex="-1">搭建Moon中转服务器 <a class="header-anchor" href="#搭建moon中转服务器" aria-label="Permalink to &quot;搭建Moon中转服务器&quot;">​</a></h2><h3 id="生成moon-json" tabindex="-1">生成moon.json <a class="header-anchor" href="#生成moon-json" aria-label="Permalink to &quot;生成moon.json&quot;">​</a></h3><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/lib/zerotier-one/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zerotier-idtool</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> initmoon</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> identity.public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> moon.json</span></span></code></pre></div><p>修改刚刚生成的配置文件moon.json，（主要是添加公网IP，公网IP是服务器的IP，9993是zerotier的默认端口，你服务器防火墙上需要开放UDP:9993,否则是连接不上Moon的）</p><p>修改stableEndpoints</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> &quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;xxxxx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> &quot;objtype&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;world&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> &quot;roots&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   &quot;identity&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;xxxx:0:eeee&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   &quot;stableEndpoints&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;10.10.0.0/9993&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> &quot;signingKey&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;asdfasdfasdf&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> &quot;signingKey_SECRET&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;asdfasdfasdfasd&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> &quot;updatesMustBeSignedBy&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;asdfasdfasdf&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> &quot;worldType&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;moon&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>此处的10.10.0.0就是公网IP，这你自己服务器的IP地址</p><h3 id="生成签名文件" tabindex="-1">生成签名文件 <a class="header-anchor" href="#生成签名文件" aria-label="Permalink to &quot;生成签名文件&quot;">​</a></h3><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zerotier-idtool</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> genmoon</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> moon.json</span></span></code></pre></div><p>执行之后会生产一个000000xxxx.moon的文件，将这个文件通过sz下载到本地</p><h3 id="将moon节点加入网络" tabindex="-1">将moon节点加入网络 <a class="header-anchor" href="#将moon节点加入网络" aria-label="Permalink to &quot;将moon节点加入网络&quot;">​</a></h3><p>创建moons.d文件夹，并把签名文件移动到文件夹内</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/lib/zerotier-one/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> moons.d</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 000000xxxxxx.moon</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> moons.d/</span></span></code></pre></div><p>此处的000000xxxxxx.moon是上一步生成的文件名</p><h3 id="重启中转服务器的-zerotier-one" tabindex="-1">重启中转服务器的 zerotier-one <a class="header-anchor" href="#重启中转服务器的-zerotier-one" aria-label="Permalink to &quot;重启中转服务器的 zerotier-one&quot;">​</a></h3><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zerotier-one</span></span></code></pre></div><p>到这里，服务器的moon就配置完成了。</p><h2 id="客户端配置" tabindex="-1">客户端配置 <a class="header-anchor" href="#客户端配置" aria-label="Permalink to &quot;客户端配置&quot;">​</a></h2><p>对客户端安装zerotier后，将配置好的moon文件配置到客户端，并重启zerotier完成与moon的连接。</p><h3 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h3><p>将之前下载的文件配置到对应路径</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/lib/zerotier-one/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> moons.d</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> username@xxxxx:/var/lib/zerotier-one/moons.d/000000xxxxxxxx.moon</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/lib/zerotier-one/moons.d</span></span></code></pre></div><p>使用之前步骤中 moon.json 文件中的 id 值 (10 位的字符串，就是xxxxxx），不知道的话在<strong>moon服务器</strong>上执行如下命令可以得到id。</p><p>执行命令：<code>grep id /var/lib/zerotier-one/moon.json | head -n 1</code></p><p>然后在客户端机器里执行命令：</p><p>执行命令：<code>zerotier-cli orbit ed2c88f24 ed2c88f24</code>，<strong>注意，这里id有两次</strong></p><p>此处的ed2c88f24刚刚在服务器里生成moon.json得到的ID值</p><h3 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h3><p>打开服务程序services.msc, 找到服务&quot;ZeroTier One&quot;, 并且在属性内找到该服务可执行文件路径,并且在其下建立moons.d文件夹,然后将moon服务器下生成的000xxxx.moon文件,拷贝到此文件夹内..再重启该服务即可(计算机右键管理-找到服务双击打开-找到zerotier one右键重新启动即可)</p><p>路径一般是Windows: C:\\ProgramData\\ZeroTier\\One</p><h3 id="mac-os" tabindex="-1">MAC OS <a class="header-anchor" href="#mac-os" aria-label="Permalink to &quot;MAC OS&quot;">​</a></h3><p>路径在<code>/Library/Application Support/ZeroTier/One/</code>,其他跟linux无区别</p><h3 id="测试是否成功" tabindex="-1">测试是否成功 <a class="header-anchor" href="#测试是否成功" aria-label="Permalink to &quot;测试是否成功&quot;">​</a></h3><p>执行命令：<code>sudo zerotier-cli listpeers</code>，若有出现你的服务器IP地址,即可证明moon连接成功</p><p>完成客户端配置</p><h2 id="取消orbit" tabindex="-1">取消Orbit <a class="header-anchor" href="#取消orbit" aria-label="Permalink to &quot;取消Orbit&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zerotier-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deorbit</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worldid</span></span></code></pre></div>`,45)])])}const c=i(t,[["render",l]]);export{F as __pageData,c as default};
